case 'department_search':$t=trim(ot_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT kd_dept,nm_dept,dept_type FROM dept WHERE status='ACTIVE' AND (?='' OR kd_dept LIKE ? OR nm_dept LIKE ? OR dept_type LIKE ?) ORDER BY kd_dept LIMIT 30",array($t,$like,$like,$like));ot_select2($rows,'kd_dept',function($r){return $r->kd_dept.' - '.$r->nm_dept.' ['.$r->dept_type.']';});
case 'cost_center_search':$t=trim(ot_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT cost_center_code,cost_center_name FROM erp_cost_center WHERE status='Aktif' AND (?='' OR cost_center_code LIKE ? OR cost_center_name LIKE ?) ORDER BY cost_center_code LIMIT 30",array($t,$like,$like));ot_select2($rows,'cost_center_code',function($r){return $r->cost_center_code.' - '.$r->cost_center_name;});
case 'attendance_search':$t=trim(ot_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT a.id,a.attendance_no,a.employee_id,a.employee_no,e.full_name,a.department_code,a.shift_schedule_id,a.assignment_no,a.attendance_date,a.planned_end,a.actual_clock_out,a.overtime_hours FROM erp_attendance a JOIN erp_employee_master e ON e.id=a.employee_id WHERE a.overtime_hours>0 AND a.attendance_status IN ('APPROVED','POSTED') AND (?='' OR a.attendance_no LIKE ? OR a.employee_no LIKE ? OR e.full_name LIKE ?) ORDER BY a.attendance_date DESC LIMIT 30",array($t,$like,$like,$like));ot_select2($rows,'id',function($r){return $r->attendance_no.' - '.$r->employee_no.' '.$r->full_name.' ['.$r->attendance_date.' / OT '.$r->overtime_hours.'h]';});
case 'attendance_info':$r=$db->fetch("SELECT a.*,e.full_name,d.nm_dept FROM erp_attendance a JOIN erp_employee_master e ON e.id=a.employee_id LEFT JOIN dept d ON d.kd_dept=a.department_code WHERE a.id=? LIMIT 1",array((int)ot_p('attendance_id')));if(!$r)ot_json('error',hr_t('hr_attendance_not_found', 'Attendance not found.'));ot_json('good','',array('employee_id'=>$r->employee_id,'employee_text'=>$r->employee_no.' - '.$r->full_name,'department_code'=>$r->department_code,'department_text'=>$r->department_code.' - '.$r->nm_dept,'shift_schedule_id'=>$r->shift_schedule_id,'assignment_no'=>$r->assignment_no,'overtime_date'=>$r->attendance_date,'planned_start'=>$r->planned_end?str_replace(' ','T',substr($r->planned_end,0,16)):'','planned_end'=>$r->actual_clock_out?str_replace(' ','T',substr($r->actual_clock_out,0,16)):'','actual_start'=>$r->planned_end?str_replace(' ','T',substr($r->planned_end,0,16)):'','actual_end'=>$r->actual_clock_out?str_replace(' ','T',substr($r->actual_clock_out,0,16)):'','requested_hours'=>$r->overtime_hours,'approved_hours'=>$r->overtime_hours,'payable_hours'=>$r->overtime_hours));
