case 'save':
  $id=(int)ot_p('id');$no=ot_c(ot_p('overtime_no'));$emp=(int)ot_p('employee_id');$date=trim(ot_p('overtime_date'));$type=ot_c(ot_p('overtime_type','REGULAR_OT'));$source=ot_c(ot_p('request_source','MANUAL'));$status=ot_c(ot_p('overtime_status','DRAFT'));$reason=trim(ot_p('overtime_reason'));
  if($no==='')ot_json('error','Overtime No wajib diisi.');if(!preg_match('/^[A-Z0-9_-]{3,30}$/',$no))ot_json('error','Overtime No hanya boleh huruf besar, angka, underscore, atau dash.');if(!$emp)ot_json('error','Employee wajib dipilih.');if(!ot_date_ok($date))ot_json('error','Overtime Date wajib format YYYY-MM-DD.');if($reason==='')ot_json('error','Overtime Reason wajib diisi.');if(!in_array($type,$types,true)||!in_array($source,$sources,true)||!in_array($status,$statuses,true))ot_json('error','Type/source/status tidak valid.');
