  if(in_array($status,array('REQUESTED','APPROVED','POSTED'),true)&&$id===0){$data['requested_by']=$username;$data['requested_at']=date('Y-m-d H:i:s');}if($status==='APPROVED'){$data['approved_by']=$username;$data['approved_at']=date('Y-m-d H:i:s');}if($status==='POSTED'){$data['posted_by']=$username;$data['posted_at']=date('Y-m-d H:i:s');}
