  if(!$ok)ot_json('error',$db->getErrorMessage()?:'Overtime gagal disimpan.');if(function_exists('simpan_log'))simpan_log('User '.$username.' menyimpan Overtime '.$no.' untuk employee '.$e->employee_no.' pada '.date('Y-m-d H:i:s'),$username);ot_json('good','Overtime berhasil disimpan.',array('id'=>$id,'estimated_amount'=>$amount));
case 'status':$id=(int)ot_p('id');$status=ot_c(ot_p('status'));if(!in_array($status,$statuses,true))ot_json('error','Status tidak valid.');$r=$db->fetch("SELECT * FROM erp_overtime WHERE id=? LIMIT 1",array($id));if(!$r)ot_json('error','Overtime tidak ditemukan.');$data=array('overtime_status'=>$status,'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s'));if($status==='APPROVED'){$data['approved_by']=$username;$data['approved_at']=date('Y-m-d H:i:s');$data['approved_hours']=$r->approved_hours>0?$r->approved_hours:$r->requested_hours;$data['payable_hours']=$r->payable_hours>0?$r->payable_hours:$r->requested_hours;$data['estimated_amount']=($data['payable_hours']*$r->rate_multiplier*$r->hourly_rate);}if($status==='POSTED'){$data['posted_by']=$username;$data['posted_at']=date('Y-m-d H:i:s');}$ok=$db->update('erp_overtime',$data,'id',$id);if(!$ok)ot_json('error',$db->getErrorMessage()?:'Status gagal diubah.');ot_json('good','Status berhasil diubah.');
